import java.util.*;public class Q2 {    public static void main(String[] args) {        Scanner sc = new Scanner(System.in);        int n = sc.nextInt();        int[] a = new int[n];        for(int i = 0; i < n; i ++) {            a[i] = sc.nextInt();        }        System.out.println(TeamForm(n, a));    }    public static int TeamForm(int n, int[] a) {        if(n == 2) {            return Math.abs(a[1] - a[0]);        }        int sum = 0;        Arrays.sort(a);        for(int i = 0; i < n-1; i +=2) {            sum += Math.abs(a[i] - a[i+1]);        }        return sum;    }}